<?php

class InvoiceDownloader
{
    private string $logoService;
    private string $logoUser;
    private string $logoPass;

    public function __construct()
    {
        $this->logoService = "https://pb.elogo.com.tr/PostBoxService.svc?wsdl";
        $this->logoUser = "";
        $this->logoPass = "";
    }



    public function run(): void
    {
        $user = "";
        $pass = "";
        $result = null;

        if ($_SERVER["REQUEST_METHOD"] === "POST" && isset($_POST["login_test"])) {
            $user = trim($_POST["user"] ?? "");
            $pass = trim($_POST["pass"] ?? "");
            $result = $this->loginTest($user, $pass);
        }

        $this->renderLoginTestUI([
            'user' => $user,
            'pass' => $pass,
            'result' => $result,
        ]);
    }

    private function loginTest(string $user, string $pass): array
    {
        try {
            $client = new SoapClient($this->logoService);
            $response = $client->login([
                'login' => [
                    'userName' => $user,
                    'passWord' => $pass,
                    'version' => '1.0',
                ],
            ]);

            $session = $response->LoginResult->sessionID ?? ($response->sessionID ?? '');

            return [
                'success' => !empty($session),
                'session' => $session,
                'response' => $response,
                'message' => empty($session)
                    ? 'Oturum alınamadı. Response içinde hata olabilir.'
                    : 'Login başarılı.',
            ];
        } catch (Throwable $e) {
            return [
                'success' => false,
                'error' => $e->getMessage(),
                'response' => null,
            ];
        }
    }

    private function renderLoginTestUI(array $data): void
    {
        $status = $data['result']['success'] ?? null;
        $message = $data['result']['message'] ?? ($data['result']['error'] ?? '');
